(function () {
  function addStyle() { if (document.getElementById('bc-style')) return; var s = document.createElement('style'); s.id = 'bc-style'; s.textContent = '.bc-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.bc-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:12px}.bc-grid label{display:flex;flex-direction:column;gap:5px;color:#334155}.bc-grid input{padding:8px;border:1px solid #cbd5e1;border-radius:8px}.bc-step{margin-top:12px;padding:12px;background:#f8f9fa;border-radius:8px;line-height:1.7}.bc-result{margin-top:10px;padding:12px;border-radius:8px;background:#d4edda;border-left:4px solid #28a745;font-size:18px}.bc-note{color:#64748b;font-size:13px;margin:8px 0}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.bcMounted) return; host.dataset.bcMounted = '1'; addStyle(); host.innerHTML = '<div class="bc-wrap"><h4>🧪 Máy tính Định lý Bayes</h4><p class="bc-note">Ví dụ xét nghiệm y khoa: bệnh hiếm, xét nghiệm nhạy, nhưng dương tính giả vẫn quan trọng.</p><div class="bc-grid"><label>P(A) <input data-pa type="number" min="0" max="1" step="0.001" value="0.001"></label><label>P(B|A) <input data-pba type="number" min="0" max="1" step="0.001" value="0.99"></label><label>P(B|not A) <input data-pbna type="number" min="0" max="1" step="0.001" value="0.01"></label></div><button type="button" data-calc style="margin-top:12px">Tính P(A|B)</button><div class="bc-step"></div><div class="bc-result"></div></div>'; var step = host.querySelector('.bc-step'), result = host.querySelector('.bc-result'); function val(sel) { var x = parseFloat(host.querySelector(sel).value); return Number.isFinite(x) ? Math.max(0, Math.min(1, x)) : 0; } function calc() { var pa = val('[data-pa]'), pba = val('[data-pba]'), pbna = val('[data-pbna]'), pna = 1 - pa, num = pba * pa, den = num + pbna * pna, post = den ? num / den : 0; step.innerHTML = 'P(A|B) = P(B|A)×P(A) / [P(B|A)×P(A) + P(B|not A)×P(not A)]<br>P(not A) = 1 - ' + pa + ' = ' + pna.toFixed(6) + '<br>Tử số = ' + pba + ' × ' + pa + ' = ' + num.toFixed(6) + '<br>Mẫu số = ' + num.toFixed(6) + ' + ' + pbna + ' × ' + pna.toFixed(6) + ' = ' + den.toFixed(6); result.innerHTML = 'P(A|B) = <strong>' + post.toFixed(4) + '</strong> ≈ <strong>' + (post * 100).toFixed(2) + '%</strong>'; } host.querySelector('[data-calc]').addEventListener('click', calc); host.querySelectorAll('input').forEach(function (i) { i.addEventListener('input', calc); }); calc(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="bayes-calculator"]').forEach(mount); });
}());
